   209|      routingPolicy = 'production_explicit';
   210|      activeBaseUrl = envConfiguredBaseUrl;
   211|      selectionReason = 'Production Owner AI routing is explicitly pinned by EXPO_PUBLIC_IVX_OWNER_AI_BASE_URL.';
   212|    } else {
   213|      routingPolicy = 'production_canonical';
   214|      activeBaseUrl = IVX_CANONICAL_API_BASE_URL;
   215|      selectionReason = envConfiguredBaseUrl
   216|        ? `Production Owner AI routing pinned to the canonical IVX API host because the configured override (${envConfiguredBaseUrl}) looks like a development host.`
   217|        : 'Production Owner AI routing pinned to the canonical IVX API host (https://api.ivxholding.com).';
   218|    }
   219|  } else if (envConfiguredBaseUrl && !isDevLikeBaseUrl(envConfiguredBaseUrl)) {
   220|    // Owner AI is hard-pinned to a non-dev host. Honor the explicit override.
   221|    routingPolicy = 'development_explicit';
   222|    activeBaseUrl = envConfiguredBaseUrl;
   223|    selectionReason = envConfiguredBaseUrl === IVX_CANONICAL_API_BASE_URL
   224|      ? 'Development build is explicitly pinned to the canonical IVX API host.'
   225|      : `Development build is explicitly pinned by ${configuredFrom ?? 'environment configuration'}.`;
   226|  } else {
   227|    // Owner AI must always reach the production backend (api.ivxholding.com)
   228|    // because the AI provider gateway, key, and rate-limit account only live
   229|    // there. Dev hosts (ivxtest.dev / web preview origin / LAN IPs) cannot
   230|    // serve POST /api/ivx/owner-ai, so we never fall back to them.
   231|    routingPolicy = 'development_canonical';
   232|    activeBaseUrl = IVX_CANONICAL_API_BASE_URL;
   233|    fallbackUsed = !!envConfiguredBaseUrl;
   234|    fallbackReason = envConfiguredBaseUrl
   235|      ? `Ignoring dev-like Owner AI override (${envConfiguredBaseUrl}); Owner AI is pinned to the canonical IVX API host.`
