   240|  if (activeBaseUrl) {
   241|    for (const candidateUrl of buildOwnerAIUrls(activeBaseUrl)) {
   242|      pushUniqueUrl(candidateEndpoints, candidateUrl);
   243|    }
   244|  }
   245|
