   303|  );
   304|  pushUniqueString(
   305|    workflowTrace,
   306|    `Owner Route53 audit URL: ${route53AuditUrl ?? 'unconfigured'}`,
   307|  );
   308|
   309|  if (directApiBaseUrl && !configuredBaseUrl && currentEnvironment === 'production') {
   310|    pushUniqueString(
   311|      mismatchWarnings,
   312|      `EXPO_PUBLIC_API_BASE_URL points to ${directApiBaseUrl}, but production Owner AI routing does not read that variable unless EXPO_PUBLIC_IVX_OWNER_AI_BASE_URL is also set.`,
   313|    );
   314|  }
   315|
   316|  if (directApiBaseUrl && activeBaseUrl && normalizeBaseUrl(directApiBaseUrl) !== normalizeBaseUrl(activeBaseUrl)) {
   317|    pushUniqueString(
   318|      mismatchWarnings,
   319|      `App-wide API traffic points to ${directApiBaseUrl}, while Owner AI resolves through ${activeBaseUrl}. This split host path can hide the real failing backend.`,
   320|    );
   321|  }
   322|
   323|  if (currentEnvironment === 'production' && directApiBaseUrl && isDevLikeBaseUrl(directApiBaseUrl)) {
   324|    pushUniqueString(
   325|      mismatchWarnings,
   326|      `EXPO_PUBLIC_API_BASE_URL still points to a development-like host in production: ${directApiBaseUrl}.`,
   327|    );
   328|  }
   329|
   330|  if (currentEnvironment === 'production' && !configuredBaseUrl && directApiBaseUrl) {
   331|    pushUniqueString(
   332|      mismatchWarnings,
   333|      'Production Owner AI routing stays pinned to the canonical IVX API host unless EXPO_PUBLIC_IVX_OWNER_AI_BASE_URL or EXPO_PUBLIC_IVX_API_BASE_URL is set explicitly.',
   334|    );
   335|  }
   336|
   337|  if (route53AuditUrl && appApiRoute53AuditUrl && route53AuditUrl !== appApiRoute53AuditUrl) {
