   339|      mismatchWarnings,
   340|      `Route53 diagnostics differ by host: owner path ${route53AuditUrl} vs app API path ${appApiRoute53AuditUrl}.`,
   341|    );
   342|  }
   343|
   344|  const audit: IVXOwnerAIConfigAudit = {
   345|    currentEnvironment,
   346|    configuredBaseUrl,
   347|    configuredFrom,
   348|    devFallbackBaseUrl: devFallbackBaseUrl || null,
   349|    projectApiBaseUrl: projectApiBaseUrl || null,
   350|    directApiBaseUrl: directApiBaseUrl || null,
   351|    webPreviewBaseUrl: webPreviewBaseUrl || null,
   352|    canonicalBaseUrl: IVX_CANONICAL_API_BASE_URL,
   353|    activeBaseUrl,
   354|    activeHost,
   355|    directApiHost,
   356|    activeEndpoint,
   357|    explicitProductionPinApplied,
   358|    candidateEndpoints,
   359|    healthCheckUrl,
   360|    route53AuditUrl,
   361|    route53UpsertUrl,
   362|    appApiHealthCheckUrl,
   363|    appApiRoute53AuditUrl,
   364|    routingPolicy,
   365|    selectionReason,
   366|    fallbackUsed,
   367|    fallbackReason,
   368|    productionReady,
   369|    blocksRemoteRequests,
   370|    configurationError,
   371|    pointsToDevHost,
   372|    workflowTrace,
   373|    mismatchWarnings,
   374|  };
   375|
   376|  console.log('[IVXSupabaseClient] Owner AI config audit:', audit);
   377|
   378|  return audit;
