   398|type IVXAccessTokenOptions = {
   399|  forceRefresh?: boolean;
   400|};
   401|
   402|/**
   403| * True when a JWT's `exp` claim is in the past (with a small clock-skew guard).
   404| * Used to ensure we never hand a guaranteed-to-be-rejected token to the
   405| * owner-gated route, which would surface as owner_route_auth_401.
   406| */
   407|function isAccessTokenExpired(token: string): boolean {
   408|  const decoded = decodeJwtPayload(token);
   409|  const exp = decoded && typeof decoded.exp === 'number' ? decoded.exp : null;
   410|  if (exp === null) {
   411|    return false;
   412|  }
   413|  const CLOCK_SKEW_SECONDS = 5;
   414|  return exp - CLOCK_SKEW_SECONDS <= Date.now() / 1000;
   415|}
   416|
   417|async function refreshIVXSessionToken(reason: string): Promise<string | null> {
   418|  try {
   419|    const { data, error } = await supabase.auth.refreshSession();
   420|    const refreshedToken = data.session?.access_token ?? null;
   421|    if (refreshedToken) {
   422|      console.log('[IVXSupabaseClient] Access token refreshed:', { reason });
   423|      return refreshedToken;
   424|    }
   425|    if (error) {
   426|      console.log('[IVXSupabaseClient] Access token refresh failed:', { reason, message: error.message });
   427|    }
   428|  } catch (error) {
   429|    console.log('[IVXSupabaseClient] Access token refresh threw:', { reason, message: error instanceof Error ? error.message : 'unknown' });
   430|  }
   431|  return null;
   432|}
