   434|export type IVXAuthStatusSnapshot = {
   435|  tokenPresent: boolean;
   436|  tokenLength: number;
   437|  expiresInSeconds: number | null;
   438|  issuer: string | null;
   439|  matchesFrontendSupabase: boolean | null;
   440|  ownerBypassEnabled: boolean;
   441|  securityMode: string;
   442|  platform: string;
   443|};
   444|
   445|function decodeJwtPayload(token: string): { iss?: unknown; exp?: unknown } | null {
   446|  const segments = token.split('.');
   447|  if (segments.length !== 3) return null;
   448|  try {
   449|    const payloadSegment = segments[1] ?? '';
   450|    const normalized = payloadSegment.replace(/-/g, '+').replace(/_/g, '/');
   451|    const padded = normalized + '='.repeat((4 - (normalized.length % 4)) % 4);
   452|    const decoded = typeof atob === 'function'
   453|      ? atob(padded)
   454|      : Buffer.from(padded, 'base64').toString('utf8');
   455|    return JSON.parse(decoded) as { iss?: unknown; exp?: unknown };
   456|  } catch {
   457|    return null;
   458|  }
   459|}
