   461|/**
   462| * Live auth state snapshot for the IVX watchdog HUD.
   463| * Reads supabase.auth.getSession() and decodes only iss/exp (no token leak).
   464| */
   465|export async function getIVXAuthStatusSnapshot(): Promise<IVXAuthStatusSnapshot> {
   466|  const accessConfig = getIVXAccessControlConfig();
   467|  const sessionResult = await supabase.auth.getSession();
   468|  const session = sessionResult.data.session;
   469|  const accessToken = session?.access_token ?? null;
   470|  const tokenPresent = Boolean(accessToken);
   471|  const tokenLength = accessToken ? accessToken.length : 0;
   472|  let issuer: string | null = null;
   473|  let expiresInSeconds: number | null = null;
   474|  let matchesFrontendSupabase: boolean | null = null;
   475|  if (accessToken) {
   476|    const decoded = decodeJwtPayload(accessToken);
   477|    if (decoded) {
   478|      issuer = typeof decoded.iss === 'string' ? decoded.iss : null;
   479|      const exp = typeof decoded.exp === 'number' ? decoded.exp : null;
   480|      expiresInSeconds = exp !== null ? Math.round(exp - Date.now() / 1000) : null;
   481|      const frontendSupabaseUrl = resolveSupabaseUrl();
   482|      matchesFrontendSupabase = issuer && frontendSupabaseUrl
   483|        ? issuer.replace(/\/+$/, '').startsWith(frontendSupabaseUrl.replace(/\/+$/, ''))
   484|        : null;
   485|    }
   486|  }
   487|  return {
   488|    tokenPresent,
   489|    tokenLength,
   490|    expiresInSeconds,
   491|    issuer,
   492|    matchesFrontendSupabase,
   493|    ownerBypassEnabled: accessConfig.ownerBypassEnabled,
   494|    securityMode: accessConfig.securityMode,
   495|    platform: Platform.OS,
   496|  };
