   499|export async function getIVXAccessToken(options: IVXAccessTokenOptions = {}): Promise<string | null> {
   500|  const accessConfig = getIVXAccessControlConfig();
   501|  const sessionResult = await supabase.auth.getSession();
   502|  const session = sessionResult.data.session;
   503|  const accessToken = session?.access_token ?? null;
   504|  const expiresAtMs = session?.expires_at ? session.expires_at * 1000 : 0;
   505|  const isExpiringSoon = expiresAtMs > 0 && expiresAtMs - Date.now() < 120_000;
   506|
   507|  if ((options.forceRefresh || isExpiringSoon) && session?.refresh_token) {
   508|    const refreshedToken = await refreshIVXSessionToken(options.forceRefresh ? 'forced_retry_after_auth_rejection' : 'token_expiring_soon');
   509|    if (refreshedToken) {
   510|      return refreshedToken;
   511|    }
   512|  }
   513|
   514|  if (accessToken) {
   515|    // Never hand back a token that is already expired: sending it to the
   516|    // owner-gated route is guaranteed to produce owner_route_auth_401, which
   517|    // previously surfaced as a confusing auth failure instead of a clean
   518|    // re-authentication prompt. If a forced refresh could not replace an
   519|    // expired token, return null so the preflight surfaces OWNER_SESSION_REQUIRED.
   520|    const tokenIsExpired = isAccessTokenExpired(accessToken);
   521|    if (tokenIsExpired) {
   522|      console.log('[IVXSupabaseClient] Access token resolved', {
   523|        tokenPresent: false,
   524|        reason: 'stale_token_expired_after_failed_refresh',
   525|        securityMode: accessConfig.securityMode,
   526|      });
   527|      if (accessConfig.ownerBypassEnabled) {
   528|        return IVX_OPEN_ACCESS_OWNER_TOKEN;
   529|      }
   530|      return null;
   531|    }
   532|    console.log('[IVXSupabaseClient] Access token resolved', {
   533|      tokenPresent: true,
   534|      securityMode: accessConfig.securityMode,
   535|      ownerBypassEnabled: accessConfig.ownerBypassEnabled,
   536|      expiringSoon: isExpiringSoon,
   537|    });
