 * Supabase owner user existence + confirmation status audit.
 *
 * Uses the service role key to query auth.users for IVX_OWNER_EMAIL.
 * Prints sanitized results (no secrets, no tokens).
 */

const SUPABASE_URL = process.env.EXPO_PUBLIC_SUPABASE_URL ?? 'https://kvclcdjmjghndxsngfzb.supabase.co';
const SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY ?? '';
const OWNER_EMAIL = (process.env.IVX_OWNER_EMAIL ?? '').trim();

async function queryAuthUsers() {
  const response = await fetch(`${SUPABASE_URL}/rest/v1/auth.users?email=eq.${encodeURIComponent(OWNER_EMAIL)}&select=id,email,email_confirmed_at,created_at,last_sign_in_at,raw_app_meta_data,raw_user_meta_data`, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      apikey: SERVICE_ROLE_KEY,
      Authorization: `Bearer ${SERVICE_ROLE_KEY}`,
    },
  });
  const text = await response.text().catch(() => '');
  let body = null;
  try {
    body = JSON.parse(text);
  } catch {
    body = { raw: text.slice(0, 500) };
  }
  return {
    httpStatus: response.status,
    body,
  };
}

async function queryProfiles() {
  const response = await fetch(`${SUPABASE_URL}/rest/v1/profiles?email=eq.${encodeURIComponent(OWNER_EMAIL.toLowerCase())}&select=id,email,role,created_at`, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      apikey: SERVICE_ROLE_KEY,
      Authorization: `Bearer ${SERVICE_ROLE_KEY}`,
    },
  });
  const text = await response.text().catch(() => '');
  let body = null;
  try {
    body = JSON.parse(text);
  } catch {
    body = { raw: text.slice(0, 500) };
  }
  return {
    httpStatus: response.status,
    body,
  };
}

async function main() {
  const users = await queryAuthUsers();
  const profiles = await queryProfiles();

  const evidence = {
    auditId: `supabase-owner-${Date.now()}`,
    auditedAt: new Date().toISOString(),
    supabaseProject: SUPABASE_URL.replace(/^https?:\/\//, '').replace(/\/+$/, ''),
    ownerEmail: OWNER_EMAIL.toLowerCase(),
    authUsersHttpStatus: users.httpStatus,
    authUsersFound: Array.isArray(users.body) ? users.body.length : null,
    authUsers: Array.isArray(users.body)
      ? users.body.map((u) => ({
          id: u.id,
          email: u.email,
          emailConfirmedAt: u.email_confirmed_at,
          createdAt: u.created_at,
          lastSignInAt: u.last_sign_in_at,
          appRole: u.raw_app_meta_data?.role ?? null,
        }))
      : users.body,
    profilesHttpStatus: profiles.httpStatus,
    profilesFound: Array.isArray(profiles.body) ? profiles.body.length : null,
    profiles: Array.isArray(profiles.body)
      ? profiles.body.map((p) => ({
          id: p.id,
